#include <bits/stdc++.h>
using namespace std;
const int maxn=10;
#define int long long
int dp[maxn][1<<maxn][1<<maxn],bit[maxn],cnt[1<<maxn];
vector<int> sta;
int cal(int x){
	int ans=0;
	while(x){
		if(x%2){
			ans++;
		}
		x/=2;
	}
	return ans;
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int n,k;
	cin>>n>>k;
	for(int i=0;i<(1<<n);i++){
		if(i&(i<<1)){
			continue;
		}
		sta.push_back(i);
		cnt[i]=cal(i);
	}
	dp[0][0][0]=1;
	for(int i=1; i<=n; i++) {
		for(int j=0; j<(1<<n); j++) {
			if(j&(j<<1)){
				continue;
			}
			for(int p=0; p<(1<<n); p++) {
				if((p&(p<<1))||(j&p)||((j|p)&((j|p)<<1))) {
					continue;
				}
				for(int s=0; s<=k; s++) {
					if (s+cnt[j]>k) break;
					dp[i][j][s+cnt[j]]+=dp[i-1][p][s];
				}
			}
		}
	}
	int ans=0;
	for(int i=0; i<(1<<n); i++) {
		ans=(ans+dp[n][i][k]);
	}
	cout<<ans;
	return 0;
}
